    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

/**
 * Custom debounce hook.
 * Returns the debounced value and a boolean indicating whether a
 * debounce is currently pending (i.e. the value is "settling").
 */
function useDebounce(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);
    // Track the previous value so we only flag "pending" on an actual change.
    const previousValueRef = useRef(value);

    useEffect(() => {
        // No change -> nothing to debounce.
        if (previousValueRef.current === value) {
            return;
        }
        previousValueRef.current = value;
        setIsPending(true);

        const timeoutId = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
        }, delay);

        // Cleanup: clears the timeout on the next change AND on unmount,
        // preventing state updates on an unmounted component (no leaks).
        return () => clearTimeout(timeoutId);
    }, [value, delay]);

    return [debouncedValue, isPending];
}

/**
 * Escape any regex special characters so user input can be used safely
 * inside a RegExp without throwing or behaving unexpectedly.
 */
function escapeRegExp(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/**
 * Returns the name with the first matching substring wrapped in <mark>.
 * Case-insensitive. If query is empty, returns the plain name.
 */
function highlightMatch(name, query) {
    if (!query) {
        return name;
    }

    const escaped = escapeRegExp(query);
    // Split into [before, match, after, before, match, after, ...].
    // Capturing group keeps the matched text in the resulting array.
    const parts = name.split(new RegExp(`(${escaped})`, 'gi'));

    return parts.map((part, index) =>
        // Odd indices are the captured matches.
        part.toLowerCase() === query.toLowerCase() ? (
            <mark key={index}>{part}</mark>
        ) : (
            <React.Fragment key={index}>{part}</React.Fragment>
        )
    );
}

function ResourceList() {
    const [query, setQuery] = useState('');
    const [debouncedQuery, isPending] = useDebounce(query, 300);

    // Whitespace-only input is treated as empty.
    const normalizedQuery = debouncedQuery.trim();

    const filteredItems = useMemo(() => {
        if (!normalizedQuery) {
            return ITEMS;
        }
        const lowerQuery = normalizedQuery.toLowerCase();
        return ITEMS.filter(item =>
            item.name.toLowerCase().includes(lowerQuery)
        );
    }, [normalizedQuery]);

    return (
        <div>
            <h2>Resources</h2>

            <input
                type="text"
                value={query}
                onChange={e => setQuery(e.target.value)}
                placeholder="Search resources..."
                aria-label="Search resources"
            />

            {/* Show indicator only while a non-empty search is settling. */}
            {isPending && query.trim() && <p>Searching...</p>}

            {filteredItems.length === 0 ? (
                <p>No results found</p>
            ) : (
                <ul>
                    {filteredItems.map(item => (
                        <li key={item.id}>
                            <strong>{highlightMatch(item.name, normalizedQuery)}</strong>{' '}
                            <span>({item.category})</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default ResourceList;
```

## How each requirement is met

1. **Search input** — controlled `<input>` at the top bound to `query`.
2. **Custom 300ms debounce** — `useDebounce` hook using `setTimeout`, no lodash.
3. **Case-insensitive substring filter** — `item.name.toLowerCase().includes(...)`.
4. **"Searching..." indicator** — shown via `isPending` while the debounce timer is active.
5. **Empty input shows all** — `filteredItems` falls back to `ITEMS` when the normalized query is empty.
6. **Highlighting** — `highlightMatch` splits on a capturing regex and wraps matches in `<mark>`.
7. **"No results found"** — rendered when `filteredItems.length === 0`.
8. **Cleanup on unmount** — the `useEffect` returns `clearTimeout`, which runs on both re-render and unmount, preventing leaks/state updates after unmount.
9. **Edge cases** — `.trim()` makes whitespace-only input behave as empty; `escapeRegExp` neutralizes special characters so queries like `C++` or `(test)` never throw.

